import{_ as o,o as r,c as a,a3 as l}from"./chunks/framework.BTFg6ESq.js";const h=JSON.parse('{"title":"多模态转写","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/transcription.md","filePath":"user-guide/tools/transcription.md","lastUpdated":1778221347000}'),e={name:"user-guide/tools/transcription.md"};function n(s,t,i,d,p,g){return r(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="多模态转写" tabindex="-1">多模态转写 <a class="header-anchor" href="#多模态转写" aria-label="Permalink to &quot;多模态转写&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>多模态转写工具能利用多模态 AI 模型，从图片、音频、视频和 PDF 文档中自动提取文本内容。你可以把它理解为一个&quot;万能文字提取器&quot;——不管是图片里的文字、视频里的对话、音频里的语音，还是 PDF 里的内容，它都能帮你转写成可编辑的文本。</p><div class="tip custom-block"><p class="custom-block-title">核心场景</p><p>你有张截图想提取里面的文字？有一段会议录音想转成文字稿？有份 PDF 文档想快速提取内容？多模态转写就是帮你做这些事的。</p></div><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>四模态支持</strong>：覆盖图片、音频、视频、PDF 文档的转写，一个工具搞定所有媒体类型</li><li><strong>智能预处理</strong>：自动对长图切片、对大视频压缩抽帧，确保模型能准确识别内容</li><li><strong>任务队列管理</strong>：支持批量提交转写任务，实时监控进度，失败自动重试</li><li><strong>结果自由编辑</strong>：转写结果支持在线编辑、保存、复制、下载，还能直接发送到 AI 聊天</li><li><strong>复读自动检测</strong>：自动识别并处理模型输出中的循环复读现象，避免无意义的重复内容</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h3><p>在开始之前，你需要在 <strong>服务配置</strong> 标签页中设置一个支持多模态的 AI 模型。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>具体配置方法请参考下方的 <a href="#服务配置">功能详解 - 服务配置</a> 部分。需要先配置好 LLM 服务，才能进行转写。</p></div><h3 id="首次转写-5-步走" tabindex="-1">首次转写 5 步走 <a class="header-anchor" href="#首次转写-5-步走" aria-label="Permalink to &quot;首次转写 5 步走&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在主页中点击 <strong>多模态转写</strong> 卡片进入工具。默认会展示 <strong>工作台</strong> 标签页。</p><blockquote><p>TODO: 截图 - 工具整体界面，标注三个标签页（工作台、任务监控、服务配置）</p></blockquote><p><strong>第二步：导入文件</strong></p><p>将文件拖放到工作台的预览区域，或点击 <strong>选择文件</strong> 按钮来选取文件。</p><p>支持的格式：</p><ul><li>图片：<code>.png</code>、<code>.jpg</code>、<code>.jpeg</code></li><li>音频：<code>.mp3</code>、<code>.wav</code></li><li>视频：<code>.mp4</code>、<code>.mkv</code></li><li>文档：<code>.pdf</code></li><li>纯文本：<code>.txt</code>、<code>.md</code>（会自动展示内容，无需转写）</li></ul><blockquote><p>TODO: 截图 - 工作台预览区，展示拖放区域和选择文件按钮</p></blockquote><p><strong>第三步：开始转写</strong></p><p>文件导入后，点击工具栏的 <strong>开始转写</strong> 按钮。你也可以先打开右上角的 <strong>自动转写</strong> 开关，这样文件导入后会立即自动开始转写。</p><blockquote><p>TODO: 截图 - 标注工具栏的&quot;开始转写&quot;按钮和&quot;自动转写&quot;开关</p></blockquote><p><strong>第四步：等待处理</strong></p><p>转写过程会在后台进行。你可以在 <strong>任务监控</strong> 标签页查看进度，或在 <strong>工作台</strong> 右侧编辑区等待结果出现。</p><blockquote><p>TODO: 截图 - 任务监控页面的任务列表，展示不同状态的任务</p></blockquote><p><strong>第五步：使用结果</strong></p><p>转写完成后，右侧编辑器会显示结果。你可以：</p><ul><li><strong>编辑</strong>：直接在编辑器中修改内容</li><li><strong>保存</strong>：将修改后的内容保存到本地文件</li><li><strong>复制</strong>：一键复制到剪贴板</li><li><strong>下载</strong>：下载为 <code>.md</code> 文件</li><li><strong>发送到聊天</strong>：将结果直接发送到 AI 聊天会话</li></ul><blockquote><p>TODO: 截图 - 右侧结果编辑器，标注复制、保存、下载、发送到聊天等操作按钮</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="工作台" tabindex="-1">工作台 <a class="header-anchor" href="#工作台" aria-label="Permalink to &quot;工作台&quot;">​</a></h3><p>工作台是转写任务的核心操作界面，采用&quot;左预览 + 右编辑&quot;的双栏布局。</p><h4 id="预览区-左栏" tabindex="-1">预览区（左栏） <a class="header-anchor" href="#预览区-左栏" aria-label="Permalink to &quot;预览区（左栏）&quot;">​</a></h4><p>展示当前选中的文件内容：</p><ul><li><strong>图片</strong>：直接显示图片预览，点击可放大查看</li><li><strong>视频</strong>：内置视频播放器，支持播放控制</li><li><strong>音频</strong>：内置音频播放器，支持播放控制</li><li><strong>PDF/文档</strong>：显示文件图标和基本信息</li><li><strong>纯文本</strong>：直接展示文件内容，无需转写</li></ul><p>预览区顶部显示文件名和&quot;移除文件&quot;按钮，方便切换文件。</p><blockquote><p>TODO: 截图 - 工作台左栏预览区，展示图片预览示例</p></blockquote><h4 id="结果区-右栏" tabindex="-1">结果区（右栏） <a class="header-anchor" href="#结果区-右栏" aria-label="Permalink to &quot;结果区（右栏）&quot;">​</a></h4><p>展示转写后的文本内容，使用代码编辑器提供舒适的阅读和编辑体验。支持语法高亮（转写结果默认 Markdown 格式）。</p><p>顶部工具栏提供以下操作：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td>保存</td><td>将编辑后的内容保存到文件</td></tr><tr><td>复制结果</td><td>一键复制到剪贴板</td></tr><tr><td>发送到聊天</td><td>将结果发送到 AI 聊天会话</td></tr><tr><td>下载</td><td>将结果下载为 <code>.md</code> 文件</td></tr></tbody></table><blockquote><p>TODO: 截图 - 右栏结果编辑器，展示转写完成的Markdown内容</p></blockquote><h4 id="快捷配置面板" tabindex="-1">快捷配置面板 <a class="header-anchor" href="#快捷配置面板" aria-label="Permalink to &quot;快捷配置面板&quot;">​</a></h4><p>点击工具栏的 <strong>配置</strong> 按钮，可以展开快捷配置面板。这里的设置<strong>仅对本次转写生效</strong>，不会影响全局配置。</p><ul><li><strong>快速选择模型</strong>：选择一个专门用于本次转写的模型（可选）</li><li><strong>临时追加提示词</strong>：输入额外的指令来引导本次转写，例如&quot;请以更正式的语气转写&quot;或&quot;着重提取关键技术术语&quot;</li></ul><blockquote><p>TODO: 截图 - 展开快捷配置面板，标注模型选择器和提示词输入框</p></blockquote><h3 id="任务监控" tabindex="-1">任务监控 <a class="header-anchor" href="#任务监控" aria-label="Permalink to &quot;任务监控&quot;">​</a></h3><p>当你有多个文件需要批量转写时，任务监控页面可以帮你统一管理所有转写任务。</p><h4 id="统计卡片" tabindex="-1">统计卡片 <a class="header-anchor" href="#统计卡片" aria-label="Permalink to &quot;统计卡片&quot;">​</a></h4><p>页面顶部展示五张统计卡片，直观了解当前任务队列概况：</p><ul><li><strong>总任务</strong>：所有提交过的任务数量</li><li><strong>正在处理</strong>：当前正在执行的任务数</li><li><strong>等待中</strong>：排队等待处理的任务数</li><li><strong>已完成</strong>：成功完成的任务数</li><li><strong>失败</strong>：执行失败的任务数</li></ul><blockquote><p>TODO: 截图 - 任务监控页面的统计卡片</p></blockquote><h4 id="任务列表" tabindex="-1">任务列表 <a class="header-anchor" href="#任务列表" aria-label="Permalink to &quot;任务列表&quot;">​</a></h4><p>任务列表以表格形式展示每个任务的详细信息：</p><table tabindex="0"><thead><tr><th>列</th><th>说明</th></tr></thead><tbody><tr><td>文件名称</td><td>显示文件名和资产ID，点击可预览文件</td></tr><tr><td>状态</td><td>队列中 / 处理中（显示进度百分比）/ 已完成 / 失败 / 已取消</td></tr><tr><td>耗时</td><td>任务的执行耗时</td></tr><tr><td>创建时间</td><td>任务创建的时间</td></tr><tr><td>操作</td><td>预览、查看错误、重试、取消、查看结果等</td></tr></tbody></table><h4 id="任务操作" tabindex="-1">任务操作 <a class="header-anchor" href="#任务操作" aria-label="Permalink to &quot;任务操作&quot;">​</a></h4><p>针对不同状态的任务，提供不同的操作按钮：</p><table tabindex="0"><thead><tr><th>状态</th><th>可用操作</th></tr></thead><tbody><tr><td>队列中 / 处理中</td><td>取消任务</td></tr><tr><td>已完成</td><td>查看结果</td></tr><tr><td>失败</td><td>查看错误详情 / 重试任务</td></tr><tr><td>已取消</td><td>重试任务</td></tr></tbody></table><p><strong>重试任务</strong>时，你可以：</p><ul><li>指定一个不同的模型来重试</li><li>添加附加提示词来引导转写</li><li>开关&quot;复读检测&quot;功能</li></ul><blockquote><p>TODO: 截图 - 重试任务弹窗，标注模型选择、提示词输入、复读检测开关</p></blockquote><p>页面顶部还有一个 <strong>清空已结束任务</strong> 按钮，可以一键清理已完成、失败和已取消的任务，保持列表整洁。</p><h3 id="服务配置" tabindex="-1">服务配置 <a class="header-anchor" href="#服务配置" aria-label="Permalink to &quot;服务配置&quot;">​</a></h3><p>在使用转写功能之前，需要先在此页面配置好 AI 模型和相关参数。配置项按功能分组，以折叠面板展示。</p><h4 id="基础服务配置" tabindex="-1">基础服务配置 <a class="header-anchor" href="#基础服务配置" aria-label="Permalink to &quot;基础服务配置&quot;">​</a></h4><ul><li><strong>兜底转写模型</strong>：选择一个全局默认的多模态模型。当图片、音频、视频等分类未配置独立模型时，将使用此模型。</li><li><strong>自动开始转写</strong>：开启后，文件导入资产库后立即加入转写队列。</li><li><strong>启用复读处理</strong>：自动检测并处理模型输出中的循环复读现象。 <ul><li><strong>连续重复阈值</strong>：同一行或同一句话连续出现的次数超过此值将视为复读（默认 3 次）</li><li><strong>全局片段阈值</strong>：文本中任意片段出现的总次数超过此值将视为复读（默认 5 次）</li><li><strong>复读白名单</strong>：包含这些片段的内容不会被判定为复读，适用于固定格式的输出</li></ul></li><li><strong>通用转写 Prompt</strong>：全局默认的提示词模板，用于指导模型如何转写。支持 <code>{filename}</code> 变量。</li></ul><blockquote><p>TODO: 截图 - 基础服务配置折叠面板</p></blockquote><h4 id="性能与并发控制" tabindex="-1">性能与并发控制 <a class="header-anchor" href="#性能与并发控制" aria-label="Permalink to &quot;性能与并发控制&quot;">​</a></h4><ul><li><strong>最大并发任务数</strong>：同时进行的转写任务数量（默认 2），较大的并发数能加速批量处理</li><li><strong>执行延迟</strong>：每个任务开始前的等待时间（默认 300ms），用于控制请求频率，避免触发 API 限流</li><li><strong>最大重试次数</strong>：转写失败时的自动重试次数（默认 2 次）</li><li><strong>超时时间</strong>：单个转写任务的最大等待时间（默认 120 秒）</li></ul><blockquote><p>TODO: 截图 - 性能与并发控制折叠面板</p></blockquote><h4 id="各模态独立配置" tabindex="-1">各模态独立配置 <a class="header-anchor" href="#各模态独立配置" aria-label="Permalink to &quot;各模态独立配置&quot;">​</a></h4><p>针对图片、音频、视频、文档四种模态，分别提供独立的配置项：</p><p><strong>通用配置项（所有模态共有）：</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>独立模型</td><td>为当前模态指定专用模型，留空则使用兜底模型</td></tr><tr><td>Prompt</td><td>当前模态专用的提示词模板</td></tr><tr><td>温度</td><td>控制输出的随机性，越低越确定性（默认 0.2）</td></tr><tr><td>最大 Token</td><td>转写结果的最大 token 数</td></tr></tbody></table><p><strong>图片特有配置：</strong></p><ul><li><strong>启用智能切片</strong>：对于长图（如聊天记录截图），自动识别空白区域进行切分，避免模型丢失细节 <ul><li><strong>宽高比阈值</strong>：图片长宽比超过此值时触发智能切图（默认 3:1）</li><li><strong>最小切片高度</strong>：切片的最小高度，防止切图太碎（默认 800px）</li></ul></li></ul><blockquote><p>TODO: 截图 - 图片转写配置折叠面板</p></blockquote><p><strong>音频特有配置：</strong></p><ul><li><strong>启用音频压缩</strong>：当音频体积超过限制时，自动压缩以减少上传体积（需配置 FFmpeg）</li><li><strong>体积限制</strong>：音频体积限制（默认 10MB），超过将尝试压缩</li><li><strong>目标比特率</strong>：压缩后的音频比特率，较低可显著减小体积但损失音质</li></ul><p><strong>视频特有配置：</strong></p><ul><li><strong>FFmpeg 路径</strong>：指定 FFmpeg 可执行文件路径（音频/视频压缩功能依赖）</li><li><strong>启用视频压缩</strong>：当视频体积超过限制时自动压缩</li><li><strong>体积限制</strong>：视频体积限制（默认 10MB），超过将尝试压缩</li><li><strong>最大帧率</strong>：压缩后的最大帧率（默认 12 FPS）</li><li><strong>最大分辨率</strong>：压缩后的最大分辨率（默认 720p）</li><li><strong>启用 GPU 加速</strong>：使用 NVIDIA GPU 加速压缩（需硬件支持）</li><li><strong>自动调整分辨率</strong>：当目标体积过小时，自动降低分辨率以保持画质</li></ul><blockquote><p>TODO: 截图 - 视频转写配置折叠面板，标注FFmpeg路径配置</p></blockquote><p><strong>文档特有配置：</strong></p><ul><li>文档配置相对简单，只有通用的模型、Prompt、温度和最大 Token 设置</li></ul><blockquote><p>TODO: 截图 - 文档转写配置折叠面板</p></blockquote><p><strong>一键重置</strong>：底部提供&quot;重置&quot;按钮，可将所有配置恢复为默认值。</p><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="批量转写" tabindex="-1">批量转写 <a class="header-anchor" href="#批量转写" aria-label="Permalink to &quot;批量转写&quot;">​</a></h3><p>想一次性处理多个文件？直接在工作台逐文件导入并开始转写，或通过资产管理系统批量导入文件到资产库（可设置自动开始转写）。</p><p>在 <strong>任务监控</strong> 页面可以查看所有任务的队列和执行情况。</p><h3 id="与-ai-聊天联动" tabindex="-1">与 AI 聊天联动 <a class="header-anchor" href="#与-ai-聊天联动" aria-label="Permalink to &quot;与 AI 聊天联动&quot;">​</a></h3><p>转写结果可以一键发送到 AI 聊天窗口，让你能基于转写后的内容继续与 AI 对话。在工作台右侧结果区点击 <strong>发送到聊天</strong> 按钮即可。</p><h3 id="自定义-prompt-模板" tabindex="-1">自定义 Prompt 模板 <a class="header-anchor" href="#自定义-prompt-模板" aria-label="Permalink to &quot;自定义 Prompt 模板&quot;">​</a></h3><p>如果你有特定的转写需求，可以在 <strong>服务配置</strong> 中自定义 Prompt 模板。系统内置的默认模板已经覆盖了大多数场景，但你完全可以按需调整：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## 任务</span></span>
<span class="line"><span>对媒体内容进行高精度多模态文本化转录。正在处理文件：{filename}。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 核心原则</span></span>
<span class="line"><span>1. **视觉优先**：仅转录和描述视觉/听觉上明确存在的内容...</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>每个模态都可以设置独立的 Prompt 模板，让你能针对不同媒体类型做精细控制。</p><h3 id="重试时指定模型" tabindex="-1">重试时指定模型 <a class="header-anchor" href="#重试时指定模型" aria-label="Permalink to &quot;重试时指定模型&quot;">​</a></h3><p>当某个转写任务失败时，你可以在重试时选择一个不同的模型来尝试。这在某些模型对特定类型内容处理不佳时非常有用——比如一个模型对图片文字识别不好，换个模型可能就好了。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-为什么我的转写一直停在-处理中" tabindex="-1">Q：为什么我的转写一直停在&quot;处理中&quot;？ <a class="header-anchor" href="#q-为什么我的转写一直停在-处理中" aria-label="Permalink to &quot;Q：为什么我的转写一直停在&quot;处理中&quot;？&quot;">​</a></h3><p>可能的原因：</p><ol><li><strong>模型服务响应慢</strong>：检查 LLM 服务是否正常工作，可以尝试在 AI 聊天中测试同一模型</li><li><strong>文件体积过大</strong>：大文件需要先进行压缩/预处理，特别是视频文件，首次处理可能需要一定时间</li><li><strong>并发数限制</strong>：如果同时有多个任务在跑，新任务会排队等待。可以在 <strong>服务配置</strong> 中调整&quot;最大并发任务数&quot;</li></ol><h3 id="q-转写结果出现大量重复内容怎么办" tabindex="-1">Q：转写结果出现大量重复内容怎么办？ <a class="header-anchor" href="#q-转写结果出现大量重复内容怎么办" aria-label="Permalink to &quot;Q：转写结果出现大量重复内容怎么办？&quot;">​</a></h3><p>这可能是模型产生了&quot;复读&quot;现象。你可以：</p><ol><li>确保启用了&quot;复读检测&quot;功能（默认开启）</li><li>在 <strong>服务配置</strong> 中调整&quot;连续重复阈值&quot;和&quot;全局片段阈值&quot;</li><li>如果某些固定格式的内容总是被误判，可以将其添加到&quot;复读白名单&quot;中</li></ol><h3 id="q-视频转写太慢了-怎么加速" tabindex="-1">Q：视频转写太慢了，怎么加速？ <a class="header-anchor" href="#q-视频转写太慢了-怎么加速" aria-label="Permalink to &quot;Q：视频转写太慢了，怎么加速？&quot;">​</a></h3><p>视频转写涉及到压缩、抽帧等预处理步骤，确实比较耗时。可以尝试：</p><ol><li>在 <strong>服务配置 &gt; 视频转写配置</strong> 中降低&quot;最大分辨率&quot;和&quot;最大帧率&quot;来减少预处理负载</li><li>如果硬件支持，开启&quot;GPU 加速&quot;来加快压缩速度</li><li>减少&quot;体积限制&quot;，让视频压缩得更小</li><li>在 <strong>服务配置 &gt; 性能与并发控制</strong> 中增加&quot;最大并发任务数&quot;</li></ol><h3 id="q-为什么音频-视频转写需要-ffmpeg" tabindex="-1">Q：为什么音频/视频转写需要 FFmpeg？ <a class="header-anchor" href="#q-为什么音频-视频转写需要-ffmpeg" aria-label="Permalink to &quot;Q：为什么音频/视频转写需要 FFmpeg？&quot;">​</a></h3><p>当音频或视频文件体积超过设定的&quot;体积限制&quot;时，系统需要使用 FFmpeg 对文件进行压缩，以减小上传到 AI 模型的体积。如果未配置 FFmpeg 路径，体积超标的媒体文件会尝试直接上传——但可能会因文件过大而失败。</p><p>你可以在 <a href="https://ffmpeg.org/" target="_blank" rel="noreferrer">FFmpeg 官网</a> 下载并安装，然后在 <strong>服务配置 &gt; 视频转写配置</strong> 中指定路径。</p><h3 id="q-转写结果可以保存到哪里" tabindex="-1">Q：转写结果可以保存到哪里？ <a class="header-anchor" href="#q-转写结果可以保存到哪里" aria-label="Permalink to &quot;Q：转写结果可以保存到哪里？&quot;">​</a></h3><p>转写结果会自动保存为资产的&quot;衍生数据&quot;，存放在资产目录下。在工作台中，你可以：</p><ul><li>点击 <strong>保存</strong> 按钮将当前编辑的内容保存到文件中</li><li>点击 <strong>下载</strong> 按钮将结果下载为 <code>.md</code> 文件到本地</li><li>通过 <strong>资产管理系统</strong> 查看和管理所有资产的转写结果</li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>转写结果以 Markdown 格式保存，方便后续编辑和阅读。</p></div>`,115)])])}const c=o(e,[["render",n]]);export{h as __pageData,c as default};
